mapper.select:
SELECT s.id,s.courseName,s.collegeId,s.startDate,s.endDate,s.credits,s.optional,s.primaryAmount,s.selected,s.remark,s.academicYear,c.name collegeName,t.username teacherName
FROM course s
LEFT JOIN college c ON s.collegeId = c.id
LEFT JOIN teacher t ON t.id=s.teacherId
WHERE s.collegeId = #{collegeId}
AND s.academicYear = #{courseAcademicYear}

SELECT id,studentId,courseId,teacherId,isQualified,creditsRemark,state
FROM student_course_rel
WHERE courseId=#{courseId}
AND studentId=#{studentId}

SELECT id, optional, selected
FROM course
WHERE id=#{courseId}

SELECT s.id,s.courseName,s.collegeId,s.startDate,s.endDate,s.credits,s.optional,s.primaryAmount,s.selected,s.remark,s.academicYear,s.classPlace,s.classDate,
       c.name collegeName,t.username teacherName,
       CASE WHEN sc.id IS NOT NULL THEN '1' ELSE '0' END as type
FROM course s
LEFT JOIN college c ON s.collegeId = c.id
LEFT JOIN teacher t ON t.id=s.teacherId
LEFT JOIN student_course_rel sc ON sc.courseId = s.id AND sc.studentId = #{studentId}
WHERE s.collegeId = #{collegeId}
AND s.academicYear != #{academicYear}
ORDER BY s.academicYear, s.courseName

SELECT s.id,s.courseName,s.collegeId,s.startDate,s.endDate,s.credits,s.optional,s.primaryAmount,s.selected,s.remark,s.academicYear,s.classPlace,s.classDate,
       c.name collegeName,t.username teacherName,
       CASE WHEN sc.id IS NOT NULL THEN '1' ELSE '0' END as type
FROM course s
LEFT JOIN college c ON s.collegeId = c.id
LEFT JOIN teacher t ON t.id=s.teacherId
LEFT JOIN student_course_rel sc ON sc.courseId = s.id AND sc.studentId = #{studentId}
WHERE s.collegeId != #{collegeId}
AND s.academicYear = #{academicYear}
ORDER BY c.name, s.courseName
